#include <stdio.h>
#include <stdlib.h>

int canSplit(int *nums, int n, int k, long long maxSum) {
    int cnt = 1;
    long long cur = 0;
    for (int i = 0; i < n; ++i) {
        if (cur + nums[i] > maxSum) {
            ++cnt;
            cur = nums[i];
            if (cnt > k) return 0;
        } else {
            cur += nums[i];
        }
    }
    return 1;
}

long long solveCase(int *nums, int n, int k) {
    long long low = 0, high = 0;
    for (int i = 0; i < n; ++i) {
        if (nums[i] > low) low = nums[i];
        high += nums[i];
    }
    long long ans = high;
    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (canSplit(nums, n, k, mid)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return ans;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, K; scanf("%d %d", &N, &K);
        int *arr = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &arr[i]);
        long long res = solveCase(arr, N, K);
        printf("%lld\n", res);
        free(arr);
    }
    return 0;
}

