import sys

def can_split(nums, k, max_sum):
    cnt = 1
    cur = 0
    for x in nums:
        if cur + x > max_sum:
            cnt += 1
            cur = x
            if cnt > k:
                return False
        else:
            cur += x
    return True

def solve_case(nums, k):
    low = max(nums)
    high = sum(nums)
    ans = high
    while low <= high:
        mid = (low + high) // 2
        if can_split(nums, k, mid):
            ans = mid
            high = mid - 1
        else:
            low = mid + 1
    return ans

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        K = int(next(it))
        nums = [int(next(it)) for _ in range(N)]
        out.append(str(solve_case(nums, K)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

